import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.widget.TextView;

public class ShareReceiver extends Activity {
    @Override
    protected void onCreate(final Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        setContentView(R.layout.activity_main);
        Intent intent = getIntent();
        if (intent != null && Intent.ACTION_SEND == intent.getAction()) {
            Uri uri;
            int flags = 0;

            for (Uri part : intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)) {
                uri = part;
                flags |= Uri.parse("https://" + uri).buildUpon().scheme("content").build().flags();

                TextView text = findViewById(R.id.content);
            }

        }
    }
}

